CREATE DATABASE IF NOT EXISTS `trade_flow_fake`
  DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci;

CREATE DATABASE IF NOT EXISTS `trade_pipeline_fake`
