    DEALLOCATE PREPARE stmt;

    SET @sql = CONCAT(
      'CREATE TABLE `trade_storage_blob_', LPAD(i, 2, '0'), '` LIKE `trade_storage_blob`'
    );
    PREPARE stmt FROM @sql;
    EXECUTE stmt;
    DEALLOCATE PREPARE stmt;

    SET i = i + 1;
  END WHILE;
END //
DELIMITER ;

