  KEY `idx_archive_scan` (`content_storage_type`, `received_time`, `id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci
  COMMENT='原始数据元数据模板表';

