) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci
  COMMENT='第三方事件接入全阶段失败审计';

-- 投递熔断控制
CREATE TABLE `trade_event_delivery_control` (
  `content_type` TINYINT UNSIGNED NOT NULL COMMENT '1订单；2支付',
