  `goods_real_pay_amt` BIGINT NOT NULL DEFAULT 0,
  `goods_total_refund_amt` BIGINT NOT NULL DEFAULT 0,
  `cashier_dis_price` BIGINT NOT NULL DEFAULT 0,
  `goods_cashier_discount` DECIMAL(5,2) NOT NULL DEFAULT 0.00,
